// // This module is designed to capture a single bit input 'd' on the falling edge of the clock 'clk'. It shifts its contents right by one position with each clock cycle, discarding the most significant bit and inserting the new bit 'd' at the most significant position. The output 'q' reflects the least significant bit of the register after each clock pulse.
module top_module(input clk, input d, output q);reg [2:0] register;
  always @(posedge clk) begin
    register <= {register[1:0], d};
  end
  assign q = register[2];
endmodule
